return ['x-generator'=>'GlotPress/4.0.3','translation-revision-date'=>'2026-03-31 19:24:57+0000','plural-forms'=>'nplurals=3; plural=(n % 10 == 1 && n % 100 != 11) ? 0 : ((n % 10 >= 2 && n % 10 <= 4 && (n % 100 < 12 || n % 100 > 14)) ? 1 : 2);','project-id-version'=>'Plugins - Limit Login Attempts Reloaded – Login Security, 2FA, Brute Force Protection &amp; Firewall - Stable (latest release)','language'=>'ru','messages'=>['One-time 2FA codes will be sent to this address. Please confirm it is correct before activating. You can %1$schange your email in your user profile%2$s.'=>'Одноразовые коды двухфакторной аутентификации будут отправлены на этот адрес. Проверьте правильность адреса перед активацией. Вы можете %1$sсменить адрес электронной почты в своем профиле%2$s.','(recommended)'=>'(рекомендуется)','2FA'=>'2FA','Browser:'=>'Браузер:','Print'=>'Печать','Retry'=>'Повторить','Copy to clipboard'=>'Копировать в буфер обмена','Time:'=>'Время:','Enable 2FA'=>'Включить 2FA','Error'=>'Ошибка','User Roles'=>'Роли пользователей','You do not have sufficient permissions to access this page.'=>'У вас недостаточно прав для доступа к этой странице.','Insufficient permissions'=>'Недостаточно разрешений','Location:'=>'Местоположение:','2FA Unavailable'=>'2FA недоступен','You can also create custom user groups using a plugin that adds user grouping functionality to WordPress, to better control which users are required to use 2FA.'=>'Вы также можете создавать собственные группы пользователей с помощью плагина, добавляющего функцию группировки пользователей, чтобы лучше контролировать, какие пользователи должны использовать двухфакторную аутентификацию.','No content available for download. Please generate links first.'=>'Файлы недоступны для скачивания. Необходимо сначала создать ссылки.','Security token is missing. Please refresh the page and try again.'=>'Отсутствует токен безопасности. Обновите страницу и повторите попытку.','Failed to generate rescue codes.'=>'Не удалось сгенериро